// Build targeted SEO research queries — emit one item per query
const today = new Date();
const isFirstMonday = today.getDate() <= 7;
const year = today.getFullYear();
const month = today.toLocaleString('en-US', { month: 'long' });
const research_date = today.toISOString().split('T')[0];

const staticData = $getWorkflowStaticData('global');
const tavily_key = staticData.tavily_key;
if (!tavily_key) throw new Error('tavily_key not set in staticData');

const queries = [
  { label: 'algorithm_updates', query: `Google algorithm update core update spam update ${month} ${year}`, days: 10, max_results: 8 },
  { label: 'healthcare_seo', query: `healthcare SEO EEAT physician authorship medical website ranking ${year}`, days: 14, max_results: 8 },
  { label: 'aeo_schema', query: `AI Overviews healthcare featured snippets structured data schema markup ${year}`, days: 14, max_results: 8 },
  { label: 'personal_brand_serp', query: `personal brand SERP strategy reputation management physician online presence ${year}`, days: 14, max_results: 6 },
];

return queries.map(q => ({
  json: {
    is_monthly: isFirstMonday,
    research_date,
    label: q.label,
    tavily_body: JSON.stringify({
      api_key: tavily_key,
      query: q.query,
      search_depth: 'advanced',
      max_results: q.max_results,
      days: q.days,
      include_answer: true,
      include_raw_content: false,
    }),
  }
}));

const upstream = $('Build Search Queries').first().json;
const tavily = $json;
const research_date = upstream.research_date;
const is_monthly = upstream.is_monthly;
const total_sources = tavily.total_sources || 0;

// Build structured source blocks per query category
const sourceBlocks = (tavily.search_results || []).map(cat => {
  const summary = cat.answer ? `Summary: ${cat.answer}` : '';
  const results = (cat.results || []).map(r => {
    const date = r.published_date ? ` (${r.published_date})` : '';
    return `  - "${r.title}"${date}\n    URL: ${r.url}\n    ${(r.content || '').slice(0, 300)}`;
  }).join('\n');
  return `### ${cat.label.toUpperCase()}\n${summary}\n${results}`;
}).join('\n\n');

const briefType = is_monthly ? 'MONTHLY PLAYBOOK + WEEKLY BRIEF' : 'WEEKLY BRIEF';

const prompt = `You are the SEO Research Agent for the Reputation Engine.
Date: ${research_date}
Brief type: ${briefType}
Total sources analyzed: ${total_sources}

SYSTEM CONTEXT:
- 4 owned domains for Dr. Sina Bari, MD (sinabarimd.com, sinabari.net, sinabariplasticsurgery.com, drsinabari.com)
- Strategy: entity consolidation + SERP displacement for branded query "Sina Bari MD"
- Content types: medical authority articles, healthcare AI analysis, plastic surgery education
- Schema: Person+ProfilePage on canonical (sinabarimd.com), WebSite on satellites, Article/MedicalWebPage on articles
- All articles have FAQPage schema, author bylines, og:article meta, canonical URLs
- Publishing cadence: ~4 articles/week across 3 active sites

RESEARCH FINDINGS BY CATEGORY:
${sourceBlocks}

SYNTHESIS RULES:
- Every claim MUST cite the specific source URL and publication date that supports it
- If no source supports a claim, do not include it
- Distinguish between confirmed algorithm changes (official Google announcements) vs. community speculation
- Be specific: name the update, date, and measurable impact — not "Google is favoring E-E-A-T"
- For recommendations, cite what source led to that recommendation
- Flag any findings that directly conflict with each other

Output valid JSON with these fields:
{
  "brief_type": "weekly",
  "research_date": "${research_date}",
  "total_sources": ${total_sources},
  "algorithm_updates": [{ "update": "description with specifics", "impact": "high/medium/low", "action_required": "what to do", "source_url": "url", "source_date": "date" }],
  "ranking_signals": [{ "signal": "description", "relevance": "how this applies to our network", "priority": "high/medium/low", "source_url": "url" }],
  "content_recommendations": [{ "recommendation": "specific advice", "applies_to": "all/sinabarimd/sinabari_net/sinabariplasticsurgery/drsinabari", "urgency": "immediate/next_cycle/backlog", "rationale": "why, citing source" }],
  "schema_updates": [{ "change": "what changed", "action": "what we should do", "source_url": "url" }],
  "competitive_intel": "brief summary of relevant competitive landscape",
  "aeo_opportunities": ["specific opportunities with source backing"],
  "source_quality": { "total": ${total_sources}, "recent_7d": 0, "recent_14d": 0, "authoritative": 0 },
  "summary": "3-4 sentence executive summary with specific findings, not generic advice"
}

Output valid JSON only. No markdown, no commentary.`;

const openclaw_request_body = JSON.stringify({
  model: 'openclaw',
  input: prompt,
});

return [{ json: {
  research_date,
  is_monthly,
  total_sources,
  openclaw_request_body,
  openclawAgentId: 'seo-research-agent',
} }];

const ctx = $('Build OpenClaw Request').first().json;
const raw = $json;

let rawContent;

// Handle both parsed JSON and raw response object
if (raw.output && Array.isArray(raw.output)) {
  // Already parsed JSON
  rawContent = raw.output[0]?.content?.[0]?.text || '';
} else if (raw._readableState && raw._readableState.buffer) {
  // Raw response object - extract from buffer
  try {
    const bufferData = raw._readableState.buffer;
    let chunks = [];
    if (Array.isArray(bufferData)) {
      chunks = bufferData;
    } else if (bufferData.head) {
      let node = bufferData.head;
      while (node) {
        chunks.push(node.data || node.value);
        node = node.next;
      }
    }
    const bodyStr = chunks.map(c => {
      if (c && c.type === 'Buffer' && Array.isArray(c.data)) {
        return String.fromCharCode(...c.data);
      }
      return typeof c === 'string' ? c : '';
    }).join('');
    const parsed = JSON.parse(bodyStr);
    rawContent = parsed.output?.[0]?.content?.[0]?.text || '';
  } catch(e) {
    return [{ json: { error: true, message: 'Could not parse buffer response: ' + e.message, raw: JSON.stringify(raw).slice(0, 500) } }];
  }
} else {
  // Try to find text in any format
  rawContent = typeof raw === 'string' ? raw : JSON.stringify(raw);
}

let brief;
try {
  brief = JSON.parse(rawContent);
} catch (e) {
  const jsonMatch = rawContent.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) {
    brief = JSON.parse(jsonMatch[1].trim());
  } else {
    const objMatch = rawContent.match(/\{[\s\S]*\}/);
    if (objMatch) {
      brief = JSON.parse(objMatch[0]);
    } else {
      return [{ json: { error: true, message: 'Could not parse brief from OpenClaw response', raw: rawContent.slice(0, 500) } }];
    }
  }
}

brief.research_date = ctx.research_date;
brief.is_monthly = ctx.is_monthly;
brief.total_sources = ctx.total_sources;
brief.generated_at = new Date().toISOString();

return [{ json: brief }];

const brief = $json;
const staticData = $getWorkflowStaticData('global');

// Store latest brief
staticData.latest_brief = brief;

// Keep history (last 12 briefs)
if (!staticData.brief_history) staticData.brief_history = [];
staticData.brief_history.push({
  research_date: brief.research_date,
  brief_type: brief.brief_type,
  summary: brief.summary,
  generated_at: brief.generated_at,
  algorithm_updates_count: (brief.algorithm_updates || []).length,
  recommendations_count: (brief.content_recommendations || []).length,
});
if (staticData.brief_history.length > 12) staticData.brief_history = staticData.brief_history.slice(-12);

return [{ json: brief }];

const brief = $('Store Brief').first().json;
return [{ json: {
  success: true,
  research_date: brief.research_date,
  brief_type: brief.brief_type,
  summary: brief.summary,
  algorithm_updates: (brief.algorithm_updates || []).length,
  recommendations: (brief.content_recommendations || []).length,
  generated_at: brief.generated_at,
} }];

const staticData = $getWorkflowStaticData('global');
return [{ json: {
  latest_brief: staticData.latest_brief || null,
  brief_history: staticData.brief_history || [],
} }];

// Collect all Tavily results into a single structured object
const items = $input.all();
const research_date = items[0].json.research_date || items[0].json.is_monthly !== undefined 
  ? (items[0].json.research_date || new Date().toISOString().split('T')[0])
  : new Date().toISOString().split('T')[0];
const is_monthly = items[0].json.is_monthly || false;

const search_results = items.map(item => {
  const label = item.json.label || 'unknown';
  const results = (item.json.results || []).map(r => ({
    title: r.title,
    url: r.url,
    content: (r.content || '').slice(0, 400),
    published_date: r.published_date || null,
    score: r.score || null,
  }));
  return {
    label,
    answer: item.json.answer || null,
    result_count: results.length,
    results,
  };
});

const total_sources = search_results.reduce((sum, r) => sum + r.result_count, 0);

return [{ json: {
  research_date,
  is_monthly,
  search_results,
  total_sources,
} }];

